import{_ as e,o as a,c as o,a0 as n}from"./chunks/framework.CSK6mTG2.js";const c=JSON.parse('{"title":"KV Cache优化：从PagedAttention到MLA","description":"深入解析大模型推理中 KV Cache 的显存瓶颈与优化方案，从 PagedAttention 的分页管理到 MLA 的低秩压缩，帮助你理解现代推理引擎背后的内存优化哲学。","frontmatter":{"title":"KV Cache优化：从PagedAttention到MLA","author":"唐超","date":"2026-07-15T00:00:00.000Z","description":"深入解析大模型推理中 KV Cache 的显存瓶颈与优化方案，从 PagedAttention 的分页管理到 MLA 的低秩压缩，帮助你理解现代推理引擎背后的内存优化哲学。"},"headers":[],"relativePath":"menuAI/kv-cache-optimization.md","filePath":"menuAI/kv-cache-optimization.md"}'),r={name:"menuAI/kv-cache-optimization.md"};function i(d,t,h,p,u,s){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="kv-cache优化-从pagedattention到mla" tabindex="-1">KV Cache优化：从PagedAttention到MLA <a class="header-anchor" href="#kv-cache优化-从pagedattention到mla" aria-label="Permalink to &quot;KV Cache优化：从PagedAttention到MLA&quot;">​</a></h1><h2 id="开篇-显存去哪了" tabindex="-1">开篇：显存去哪了？ <a class="header-anchor" href="#开篇-显存去哪了" aria-label="Permalink to &quot;开篇：显存去哪了？&quot;">​</a></h2><p>你有没有这种感觉：大模型生成回答时，越往后越慢？开头几秒一个字一个字蹦，后来干脆卡住不动了。这不是模型&quot;累了&quot;，而是<strong>显存不够用了</strong>。</p><p>说白了，大模型推理时最吃显存的不是模型参数（那些权重在推理前就加载好了），而是 <strong>KV Cache</strong>——每个生成步骤里用来&quot;记忆&quot;之前所有词的中间计算结果。</p><p>今天我们就来拆解这个问题：KV Cache 是什么，为什么它成了瓶颈，以及 vLLM、DeepSeek 等主流框架是怎么&quot;省内存&quot;的。</p><h2 id="kv-cache-推理时的-草稿纸" tabindex="-1">KV Cache：推理时的&quot;草稿纸&quot; <a class="header-anchor" href="#kv-cache-推理时的-草稿纸" aria-label="Permalink to &quot;KV Cache：推理时的&quot;草稿纸&quot;&quot;">​</a></h2><p>先用一个生活场景让你理解 KV Cache 的本质。</p><p>想象你写一篇长文章，不是从头一口气写完，而是每写一个字，都要回头把前面所有字重新读一遍，然后才能决定下一个字该写什么。这听起来很蠢，但大模型的推理机制本质上就是这样工作的——<strong>自回归生成</strong>，每次预测下一个 token，都要&quot;看&quot;一遍之前所有的 token。</p><p>如果你真的每次都重新算，那代价就太大了。假设上下文有 4096 个 token，每次都要做 4096 次注意力运算，这不是在烧 GPU，这是在烧钱。</p><p>所以聪明人就想了：<strong>把每次计算出来的中间结果（Key 和 Value）缓存下来，下次直接查表</strong>。这就是 KV Cache——一张专门给 Attention 用的草稿纸，写过的内容不用重写。</p><h3 id="草稿纸越写越大" tabindex="-1">草稿纸越写越大 <a class="header-anchor" href="#草稿纸越写越大" aria-label="Permalink to &quot;草稿纸越写越大&quot;">​</a></h3><p>问题来了。这张草稿纸是画在显存里的，而且随着对话变长，它会越来越大。你生成第一个 token 时，草稿纸只有几个字；生成到第 1000 个 token 时，草稿纸上已经有 1000 组 Key-Value 了。这些数据全得存在显存里，而且是以 <strong>O(n) 的速度线性增长</strong>的。</p><p>一个粗略的数字：70B 参数的模型，每个 token 的 K 和 V 向量大概占用 1MB 显存。听起来不大？但 4096 个 token 就是 4GB，16384 个 token（大约 1 万字）就奔着 16GB 去了——要知道很多显卡的显存总共也就 24GB、48GB。</p><p>这就是 KV Cache 的核心矛盾：<strong>显存有限，上下文长度无限</strong>。</p><h2 id="pagedattention-像操作系统一样-分页" tabindex="-1">PagedAttention：像操作系统一样&quot;分页&quot; <a class="header-anchor" href="#pagedattention-像操作系统一样-分页" aria-label="Permalink to &quot;PagedAttention：像操作系统一样&quot;分页&quot;&quot;">​</a></h2><h3 id="固定座位的问题" tabindex="-1">固定座位的问题 <a class="header-anchor" href="#固定座位的问题" aria-label="Permalink to &quot;固定座位的问题&quot;">​</a></h3><p>传统方法是怎么管理 KV Cache 的呢？打个比方你就明白了。</p><p>想象你去餐厅吃饭，服务员告诉你：&quot;不好意思，您这个团体必须坐连续的空位，不能分开坐。&quot;结果你们 10 个人，但能放 10 把连续椅子的区域只剩 8 个位置，另外一个区域有 5 个位置但中间有根柱子。你们宁愿换一家餐厅，也坐不下。</p><p>这就是传统 KV Cache 的问题——<strong>预先分配固定大小的连续内存块</strong>。每个 token 的 K/V 向量组被当成一个整体，必须放在显存的一块连续区域里。一旦碎片化，明明还有足够的空闲显存，但就是凑不出&quot;连续&quot;的空间来。</p><p>结果就是：<strong>显存利用率只有 20%~40%，一大半空间都浪费在&quot;等待连续座位&quot;上了</strong>。</p><h3 id="分页管理-让碎片化不再成为问题" tabindex="-1">分页管理：让碎片化不再成为问题 <a class="header-anchor" href="#分页管理-让碎片化不再成为问题" aria-label="Permalink to &quot;分页管理：让碎片化不再成为问题&quot;">​</a></h3><p>vLLM 团队从操作系统那里学来了一招：<strong>分页管理（Paging）</strong>。</p><p>在操作系统里，物理内存是按固定大小的页（Page）来管理的。一个进程可以占用很多不连续的物理页，但操作系统维护一张页表，把虚拟地址映射到物理地址。对 KV Cache 来说，vLLM 也做了类似的事情：</p><p><strong>Block as Page</strong>：把显存分成固定大小的&quot;页&quot;（比如 16 个 token 为一页），不同的请求可以共享不同的页，不必连续。</p><p><strong>虚拟地址空间</strong>：每个请求有自己的虚拟 KV 缓存区，看起来是连续的，但从物理上看，数据散落在显存各处，按需分配。</p><p><strong>Copy-on-Write</strong>：父子请求可以共享只读页面，只有在修改时才复制（这在 Beam Search 等场景下特别有用）。</p><p>你可以把 PagedAttention 理解为：<strong>不再要求&quot;一整排连续座位&quot;，而是接受&quot;分散就座&quot;，服务生靠手里的座位图（页表）知道你们都坐在哪</strong>。</p><p>vLLM 用了 PagedAttention 之后，显存利用率从 ~20% 提升到了 ~80%，<strong>同等显存下能服务的并发请求数量翻了好几倍</strong>。这就是为什么现在很多人部署大模型，首选就是 vLLM。</p><h2 id="mla-把-笔记-压缩成-关键词" tabindex="-1">MLA：把&quot;笔记&quot;压缩成&quot;关键词&quot; <a class="header-anchor" href="#mla-把-笔记-压缩成-关键词" aria-label="Permalink to &quot;MLA：把&quot;笔记&quot;压缩成&quot;关键词&quot;&quot;">​</a></h2><h3 id="deepseek-的思路" tabindex="-1">DeepSeek 的思路 <a class="header-anchor" href="#deepseek-的思路" aria-label="Permalink to &quot;DeepSeek 的思路&quot;">​</a></h3><p>DeepSeek-V2 提出了一个不同的优化思路，叫 <strong>Multi-head Latent Attention（MLA）</strong>。它不是在管理方式上做文章，而是在&quot;存储什么&quot;上做文章。</p><p>先想一个场景：你有一个笔记本，里面密密麻麻记了 1 万字的会议记录。但你发现，每次需要参考某段内容时，你并不是真的要把那一万字全部再看一遍，你只需要一些关键要点就够了。</p><p>MLA 就是这个思路。它不直接缓存原始的 Key-Value，而是先把它们<strong>压缩到一个低维空间</strong>，只存那个压缩后的&quot;摘要&quot;，计算注意力时再临时&quot;解压&quot;出来。</p><h3 id="低秩分解-抽象画比写实画省空间" tabindex="-1">低秩分解：抽象画比写实画省空间 <a class="header-anchor" href="#低秩分解-抽象画比写实画省空间" aria-label="Permalink to &quot;低秩分解：抽象画比写实画省空间&quot;">​</a></h3><p>数学上这叫 <strong>低秩分解（Low-Rank Factorization）</strong>。说起来吓人，但类比一下很好懂。</p><p>你有一张 512×512 的人脸照片（密密麻麻的像素点），我让你只记住 64 个特征来描述这张脸：眼睛间距、鼻子长度、颧骨高度……你压缩到 64 个数，再看到这些数时，虽然不是原图，但能大概&quot;重建&quot;出这张脸的感觉——这就是低秩压缩。</p><p>MLA 的操作类似：原始的 K 矩阵是 <code>[seq_len, num_heads, head_dim]</code>，压缩后变成了一个很小的&quot;潜在向量&quot; <code>c_t^{KV}</code>，存的是 <code>num_heads × head_dim</code> 降维到 <code>low_rank_dim</code> 的结果。</p><p>推理时怎么用？每个 token 只需要<strong>解码一个额外的&quot;位置 key&quot;</strong>，结合缓存的低秩向量，就能重建出完整的注意力结果。</p><h3 id="省了多少" tabindex="-1">省了多少？ <a class="header-anchor" href="#省了多少" aria-label="Permalink to &quot;省了多少？&quot;">​</a></h3><p>粗略估算：MLA 每个 token 只存<strong>一个低秩向量 + 解码用的 key</strong>，相比原始的完整 K 矩阵，KV Cache 大小减少了约 <strong>5~8 倍</strong>。</p><p>更妙的是，这压缩过程是端到端可学习的——模型在训练时就学会了&quot;什么样的压缩方式保留了关键信息&quot;，不是简单丢弃数据，而是真的学到了一个更好的表示。</p><h2 id="除了-pagedattention-和-mla-还有什么招" tabindex="-1">除了 PagedAttention 和 MLA，还有什么招？ <a class="header-anchor" href="#除了-pagedattention-和-mla-还有什么招" aria-label="Permalink to &quot;除了 PagedAttention 和 MLA，还有什么招？&quot;">​</a></h2><p>其实这两条路代表了两个优化方向，业界还有很多有意思的实践：</p><p><strong>StreamingLLM 的&quot;锚点策略&quot;</strong>：超长对话没法把全部历史都缓存，StreamingLLM 发现保留开头几个 token（汇聚注意力）和最近几个 token，中间用滑动窗口——这个组合居然效果出奇地好，被形象地称为&quot;注意力汇聚（Attention Sink）&quot;。</p><p><strong>MQA/GQA：减少&quot;头数&quot;</strong>：Multi-Query Attention 让所有注意力头共享一份 K/V，Multi-Head Attention 有 N 个头就有 N 份 K/V，数据量差 N 倍。GQA（Grouped-Query Attention）是个折中方案，N 个 Query 头分成 G 组，每组共享一套 K/V。</p><p><strong>H2O（Heavy-Hitter Oracle）</strong>：基于一个观察——有些 token 对最终结果影响巨大（比如关键决策词），有些是&quot;凑数的&quot;。H2O 选择性地只保留那些高频出现在注意力加权里的 Heavy-Hitter，把其他的丢弃掉。</p><h2 id="怎么选" tabindex="-1">怎么选？ <a class="header-anchor" href="#怎么选" aria-label="Permalink to &quot;怎么选？&quot;">​</a></h2><p>说了这么多，你可能会问：那我实际用的时候该关注什么？</p><p>简单总结一张表：</p><table tabindex="0"><thead><tr><th>场景</th><th>推荐方案</th><th>原因</th></tr></thead><tbody><tr><td>高并发部署，多用户同时请求</td><td>PagedAttention（vLLM）</td><td>显存利用率翻倍，并发量大幅提升</td></tr><tr><td>超长上下文，32K+ token</td><td>StreamingLLM / 滑动窗口</td><td>全量缓存不现实，必须选择性保留</td></tr><tr><td>极致压缩，想省更多显存</td><td>MLA / GQA</td><td>从存储结构上动手，从根本上减少体积</td></tr><tr><td>对延迟敏感，要求实时响应</td><td>MQA</td><td>减少内存访问，延迟明显降低</td></tr></tbody></table><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>回过头来看，KV Cache 优化的故事本质上是一个<strong>工程哲学的较量</strong>：</p><p>PagedAttention 是<strong>外部优化</strong>——物理显存就那么多，我通过更聪明的管理方式把碎片化消灭掉，让每一字节都物尽其用。</p><p>MLA 是<strong>内部优化</strong>——数据本身有冗余，我从根本上压缩它，存一个&quot;精华版&quot;，用时再展开。</p><p>两条路没有绝对的好坏，更多是看你的场景侧重什么。如果你做的是高并发服务，PagedAttention 的收益是立竿见影的；如果你在做模型结构创新，MLA 的思路更值得借鉴。</p><p>显存永远是大模型推理的稀缺资源。理解它、管理它、压缩它——这才是让大模型真正走向实用的必经之路。</p>',56)])])}const l=e(r,[["render",i]]);export{c as __pageData,l as default};
